     1→import type { Compute, Serializable, Writable } from '../../helpers/type-utils';
     2→import { CacheStrategy } from './cache';
     3→import type { MachineState, SliceContext, SliceReducer } from './commons';
     4→
     5→/** Represents the payload of a reducer action. Must be serializable. */
     6→export type ActionPayload = Serializable;
     7→
     8→/** Represents a generic Redux action. */
     9→export type AnyAction = {
    10→  type: string;
    11→  [K: string]: any;
    12→};
    13→
    14→/** Distinguishes between synchronous and asynchronous slices. */
    15→export enum SliceKind {
    16→  async = 'async',
    17→  sync = 'sync',
    18→}
    19→
    20→/** The reducers config expected by createSlice **/
    21→export type SliceReducersConfig<State = any> = {
    22→  [K: string]: SliceReducer<State, any>;
    23→};
    24→
    25→/**
    26→ * Defines the structure of a synchronous slice, which manages a piece of state
    27→ * through a set of reducer functions.
    28→ */
    29→export interface Slice<
    30→  State extends MachineState,
    31→  Reducers extends SliceReducersConfig<State>,
    32→  ID extends string = string,
    33→> {
    34→  /** A unique identifier for the slice within the machine. */
    35→  id: ID;
    36→  /** The kind of slice. */
    37→  kind: SliceKind.sync;
    38→  /** The initial state of the slice. */
    39→  initial: State;
    40→  /** A record of functions that can update the slice's state. */
    41→  reducers: Reducers;
    42→  /** Defines the caching behavior for the stored state **/
    43→  cache: CacheStrategy;
    44→}
    45→
    46→/**
    47→ * Defines the standard state shape for an asynchronous slice, tracking
    48→ * loading status, data, and errors.
    49→ */
    50→export type AsyncSliceState<Value> = {
    51→  loading: boolean;
    52→  loaded: boolean;
    53→  failed: boolean;
    54→  error: string | null;
    55→  value: Value | null;
    56→  changes: number;
    57→};
    58→
    59→/**
    60→ * Defines the structure of an asynchronous slice, which manages state
    61→ * related to a data fetching operation.
    62→ */
    63→export interface AsyncSlice<
    64→  Result,
    65→  Payload extends ActionPayload,
    66→  Context extends SliceContext,
    67→  ID extends string = string,
    68→> {
    69→  /** A unique identifier for the slice within the machine. */
    70→  id: ID;
    71→  /** The kind of slice. */
    72→  kind: SliceKind.async;
    73→  /** The function that performs the asynchronous operation. */
    74→  load(payload: Payload, context: Compute<NoInfer<Context>>): Promise<Result>;
    75→  /** The runtime context required by the `load` function. */
    76→  context: Context;
    77→  /** The initial state shape for the async slice. */
    78→  initial: AsyncSliceState<Result>;
    79→  /** Defines the caching behavior for the stored state **/
    80→  cache: CacheStrategy;
    81→}
    82→
    83→/** Configuration object for creating a synchronous slice. */
    84→export type SliceConfig<
    85→  State extends MachineState,
    86→  Reducers extends SliceReducersConfig,
    87→  ID extends string = string,
    88→> = {
    89→  /** A unique identifier for the slice within the machine. */
    90→  id: ID;
    91→  /** The kind of slice. */
    92→  kind?: SliceKind.sync;
    93→  /** The initial state of the slice. */
    94→  initial: State;
    95→  /** A record of functions that can update the slice's state. */
    96→  reducers: Reducers;
    97→  /** Cache config for stored state */
    98→  cache: CacheStrategy;
    99→};
   100→
   101→/** Configuration object for creating an asynchronous slice. */
   102→export type AsyncSliceConfig<
   103→  Payload extends ActionPayload,
   104→  Result,
   105→  Context extends SliceContext,
   106→  ID extends string = string,
   107→> = {
   108→  /** A unique identifier for the slice within the machine. */
   109→  id: ID;
   110→  /** The kind of slice. */
   111→  kind?: SliceKind.async;
   112→  /** The function that performs the asynchronous operation. */
   113→  load(payload: Payload, context: Compute<NoInfer<Context>>): Promise<Result>;
   114→  /** The runtime context required by the `load` function. */
   115→  context: Writable<Context>;
   116→  /** The initial state shape for the async slice. */
   117→  initial?: AsyncSliceState<Result>;
   118→  cache: CacheStrategy;
   119→};
   120→
   121→/** Defines the signature of the `createSlice` factory function. */
   122→export interface CreateSlice {
   123→  <
   124→    State extends MachineState,
   125→    const Reducers extends SliceReducersConfig<State>,
   126→    const ID extends string,
   127→  >(
   128→    config: SliceConfig<State, Reducers, ID>,
   129→  ): Slice<State, Reducers, ID>;
   130→}
   131→
   132→/** Defines the signature of the `createAsyncSlice` factory function. */
   133→export interface CreateAsyncSlice {
   134→  <
   135→    Payload extends ActionPayload,
   136→    Result,
   137→    const Context extends SliceContext,
   138→    const ID extends string,
