import type { Compute, Serializable, Writable } from '../../helpers/type-utils';
import { CacheStrategy } from './cache';
import type { MachineState, SliceContext, SliceReducer } from './commons';

/** Represents the payload of a reducer action. Must be serializable. */
export type ActionPayload = Serializable;

/** Represents a generic Redux action. */
export type AnyAction = {
  type: string;
  [K: string]: any;
};

/** Distinguishes between synchronous and asynchronous slices. */
export enum SliceKind {
  async = 'async',
  sync = 'sync',
}

/** The reducers config expected by createSlice **/
export type SliceReducersConfig<State = any> = {
  [K: string]: SliceReducer<State, any>;
};

/**
 * Defines the structure of a synchronous slice, which manages a piece of state
 * through a set of reducer functions.
 */
export interface Slice<
  State extends MachineState,
  Reducers extends SliceReducersConfig<State>,
  ID extends string = string,
> {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind: SliceKind.sync;
  /** The initial state of the slice. */
  initial: State;
  /** A record of functions that can update the slice's state. */
  reducers: Reducers;
  /** Defines the caching behavior for the stored state **/
  cache: CacheStrategy;
}

/**
 * Defines the standard state shape for an asynchronous slice, tracking
 * loading status, data, and errors.
 */
export type AsyncSliceState<Value> = {
  loading: boolean;
  loaded: boolean;
  failed: boolean;
  error: string | null;
  value: Value | null;
  changes: number;
};

/**
 * Defines the structure of an asynchronous slice, which manages state
 * related to a data fetching operation.
 */
export interface AsyncSlice<
  Result,
  Payload extends ActionPayload,
  Context extends SliceContext,
  ID extends string = string,
> {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind: SliceKind.async;
  /** The function that performs the asynchronous operation. */
  load(payload: Payload, context: Compute<NoInfer<Context>>): Promise<Result>;
  /** The runtime context required by the `load` function. */
  context: Context;
  /** The initial state shape for the async slice. */
  initial: AsyncSliceState<Result>;
  /** Defines the caching behavior for the stored state **/
  cache: CacheStrategy;
}

/** Configuration object for creating a synchronous slice. */
export type SliceConfig<
  State extends MachineState,
  Reducers extends SliceReducersConfig,
  ID extends string = string,
> = {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind?: SliceKind.sync;
  /** The initial state of the slice. */
  initial: State;
  /** A record of functions that can update the slice's state. */
  reducers: Reducers;
  /** Cache config for stored state */
  cache: CacheStrategy;
};

/** Configuration object for creating an asynchronous slice. */
export type AsyncSliceConfig<
  Payload extends ActionPayload,
  Result,
  Context extends SliceContext,
  ID extends string = string,
> = {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind?: SliceKind.async;
  /** The function that performs the asynchronous operation. */
  load(payload: Payload, context: Compute<NoInfer<Context>>): Promise<Result>;
  /** The runtime context required by the `load` function. */
  context: Writable<Context>;
  /** The initial state shape for the async slice. */
  initial?: AsyncSliceState<Result>;
  cache: CacheStrategy;
};

/** Defines the signature of the `createSlice` factory function. */
export interface CreateSlice {
  <
    State extends MachineState,
    const Reducers extends SliceReducersConfig<State>,
    const ID extends string,
  >(
    config: SliceConfig<State, Reducers, ID>,
  ): Slice<State, Reducers, ID>;
}

/** Defines the signature of the `createAsyncSlice` factory function. */
export interface CreateAsyncSlice {
  <
    Payload extends ActionPayload,
    Result,
    const Context extends SliceContext,
    const ID extends string,
  >(
    config: AsyncSliceConfig<Payload, Result, Context, ID>,
  ): AsyncSlice<Result, Payload, Context, ID>;
}

